import React, { useMemo } from "react";

// Desktop imports
import clearDayDesktop from "./overlays/desktop/clearday.mp4";
import clearNightDesktop from "./overlays/desktop/clearnight.mp4";
import cloudyDayDesktop from "./overlays/desktop/cloudyday.mp4";
import cloudyNightDesktop from "./overlays/desktop/cloudynight.mp4";
import rainDayDesktop from "./overlays/desktop/rainday.mp4";
import rainNightDesktop from "./overlays/desktop/rainnight.mp4";
import snowDayDesktop from "./overlays/desktop/snowday.mp4";
import snowNightDesktop from "./overlays/desktop/snownight.mp4";
import thunderDayDesktop from "./overlays/desktop/thunderstormday.mp4";
import thunderNightDesktop from "./overlays/desktop/thunderstormnight.mp4";
import fogDayDesktop from "./overlays/desktop/fogday.mp4";
import fogNightDesktop from "./overlays/desktop/fognight.mp4";

// Mobile imports
import clearDayMobile from "./overlays/mobile/cleardaymobile.mp4";
import clearNightMobile from "./overlays/mobile/clearnightmobile.mp4";
import cloudyDayMobile from "./overlays/mobile/cloudydaymobile.mp4";
import cloudyNightMobile from "./overlays/mobile/cloudynightmobile.mp4";
import rainDayMobile from "./overlays/mobile/raindaymobile.mp4";
import rainNightMobile from "./overlays/mobile/rainnightmobile.mp4";
import snowDayMobile from "./overlays/mobile/snowdaymobile.mp4";
import snowNightMobile from "./overlays/mobile/snownightmobile.mp4";
import thunderDayMobile from "./overlays/mobile/thunderstormdaymobile.mp4";
import thunderNightMobile from "./overlays/mobile/thunderstormnightmobile.mp4";
import fogDayMobile from "./overlays/mobile/fogdaymobile.mp4";
import fogNightMobile from "./overlays/mobile/fognightmobile.mp4";

function normalizeCondition(cond) {
  let s = "";
  if (typeof cond === "string") s = cond;
  else if (cond && typeof cond === "object") s = cond.main || cond.description || "";
  s = String(s).toLowerCase();

  if (!s) return "clear";
  if (s.includes("thunder") || s.includes("tornado") || s.includes("squall")) return "thunder";
  if (s.includes("drizzle") || s.includes("rain")) return "rain";
  if (s.includes("snow") || s.includes("sleet") || s.includes("hail")) return "snow";
  if (s.includes("cloud")) return "cloudy";
  if (s.includes("mist") || s.includes("fog") || s.includes("haze") || s.includes("smoke")) return "fog";
  return "clear";
}

const VIDEO_MAP = {
  clear: {
    day:   { desktop: clearDayDesktop,   mobile: clearDayMobile },
    night: { desktop: clearNightDesktop, mobile: clearNightMobile },
  },
  cloudy: {
    day:   { desktop: cloudyDayDesktop,   mobile: cloudyDayMobile },
    night: { desktop: cloudyNightDesktop, mobile: cloudyNightMobile },
  },
  rain: {
    day:   { desktop: rainDayDesktop,   mobile: rainDayMobile },
    night: { desktop: rainNightDesktop, mobile: rainNightMobile },
  },
  snow: {
    day:   { desktop: snowDayDesktop,   mobile: snowDayMobile },
    night: { desktop: snowNightDesktop, mobile: snowNightMobile },
  },
  thunder: {
    day:   { desktop: thunderDayDesktop,   mobile: thunderDayMobile },
    night: { desktop: thunderNightDesktop, mobile: thunderNightMobile },
  },
  fog: {
    day:   { desktop: fogDayDesktop,   mobile: fogDayMobile },
    night: { desktop: fogNightDesktop, mobile: fogNightMobile },
  },
};

export default function WeatherOverlay({
  condition,
  isDay = true,
  device = "desktop",
  className = "",
  opacity = 0.85,
}) {
  const key = useMemo(() => normalizeCondition(condition), [condition]);
  const dayKey = isDay ? "day" : "night";
  const devKey = device === "mobile" ? "mobile" : "desktop";
  const src = VIDEO_MAP[key]?.[dayKey]?.[devKey];

  if (!src) return null;

  return (
    <div className={`fixed inset-0 -z-10 pointer-events-none ${className}`} aria-hidden="true">
      <video
        src={src}
        autoPlay
        muted
        loop
        playsInline
        className="w-full h-full object-cover"
        style={{ opacity }}
      />
    </div>
  );
}
